insert into caravan_navi_comment values (10001, 2002, 126401, 2, 'クローチェ', 'いらっしゃいませっ♪\\nキャラバンコインを使って\\n買い物ができますよっ！', 1, '2023/06/30 12:00:00', '2023/09/22 14:59:59', -470.0, 0.0, 1.47, 1, 1);
insert into caravan_navi_comment values (10002, 2002, 126401, 1, 'クローチェ', '素敵な品が揃ってるので\\nたーっくさん買っていって\\nくださいねっ♪', 2, '2023/06/30 12:00:00', '2023/09/22 14:59:59', -470.0, 0.0, 2.15, 2, 1);
insert into caravan_navi_comment values (10003, 2002, 126501, 2, 'ライラエル', 'ショップへようこそ\\nキャラバンコインはこちら\\nで買い物に使えますよ', 1, '2023/06/30 12:00:00', '2023/09/22 14:59:59', -470.0, 0.0, 0.0, 2, 1);
insert into caravan_navi_comment values (10004, 2002, 126501, 1, 'ライラエル', 'こちらのショップで\\n買い物をして、素敵な\\n旅を楽しんでくださいね', 2, '2023/06/30 12:00:00', '2023/09/22 14:59:59', -470.0, 0.0, 0.0, 1, 1);
insert into caravan_navi_comment values (10005, 2002, 127702, 2, 'リンド', 'いらっしゃいませ\\nキャラバンコインを使って\\nお買い物ができますよ', 1, '2023/09/15 15:00:00', '2023/12/22 14:59:59', -470.0, 0.0, 0.0, 2, 2);
insert into caravan_navi_comment values (10006, 2002, 127702, 2, 'リンド', 'ショップの掃除は完璧です\\n姫さま直営のお店として\\n当然のことですから', 2, '2023/09/15 15:00:00', '2023/12/22 14:59:59', -470.0, 0.0, 0.0, 2, 2);
insert into caravan_navi_comment values (10007, 2002, 127802, 1, 'ヴルム', 'ショップへようこそ\\nキャラバンコインと品物を\\n交換できるんで、よければ', 1, '2023/09/15 15:00:00', '2023/12/22 14:59:59', -470.0, 0.0, 0.0, 1, 2);
insert into caravan_navi_comment values (10008, 2002, 127802, 1, 'ヴルム', 'なんで店番なんか…\\nま、やりますけど\\n好きな品物をどうぞ', 2, '2023/09/15 15:00:00', '2023/12/22 14:59:59', -470.0, 0.0, 6.5, 2, 2);
insert into caravan_navi_comment values (10009, 2002, 129602, 1, 'アネモネ', '──いらっしゃいませ\\n買い物しても、いいですよ\\nキャラバンコインがあれば', 1, '2023/12/15 15:00:00', '2024/03/22 14:59:59', -470.0, 0.0, 0.0, 2, 3);
insert into caravan_navi_comment values (10010, 2002, 129602, 1, 'アネモネ', '──もっと笑顔がほしい？\\nいくらコインを積まれても\\n売れない物はありますから', 2, '2023/12/15 15:00:00', '2024/03/22 14:59:59', -470.0, 0.0, 0.0, 2, 3);
insert into caravan_navi_comment values (10011, 2002, 129701, 1, 'ネフィ=ネラ', 'ようこそおいでなんし\\nキャラバンコインをこちら\\nで交換して進ぜんしょう', 1, '2023/12/15 15:00:00', '2024/03/22 14:59:59', -470.0, 0.0, 0.0, 1, 3);
insert into caravan_navi_comment values (10012, 2002, 129701, 1, 'ネフィ=ネラ', 'ところで、お前さまは\\nいくらで贖えるのか喃？\\n──フフ、冗談でありんす', 2, '2023/12/15 15:00:00', '2024/03/22 14:59:59', -470.0, 0.0, 6.2, 2, 3);
insert into caravan_navi_comment values (10013, 2002, 130301, 5, 'カノン', 'い、いらっしゃいませっ！\\n…くっ…このあたくし様が\\n店番なんて…屈辱ですわっ', 1, '2024/03/15 15:00:00', '2024/06/22 14:59:59', -470.0, 0.0, 3.1, 3, 4);
insert into caravan_navi_comment values (10014, 2002, 130301, 2, 'カノン', 'あら、あたくしをご所望？\\nお生憎様、そんな小銭では\\n…買えちゃうんですの！？', 2, '2024/03/15 15:00:00', '2024/06/22 14:59:59', -470.0, 0.0, 6.15, 3, 4);
insert into caravan_navi_comment values (10015, 2002, 130401, 2, 'ナーナ', 'いらっしゃいませ～♪\\nきゃらばんこいん？を\\n交換できるんだってー', 1, '2024/03/15 15:00:00', '2024/06/22 14:59:59', -470.0, 0.0, 0.0, 2, 4);
insert into caravan_navi_comment values (10016, 2002, 130401, 1, 'ナーナ', '甘いのくれたら、\\nお礼にナーナの拾った\\n松ぼっくりあげちゃうよ！', 2, '2024/03/15 15:00:00', '2024/06/22 14:59:59', -470.0, 0.0, 3.35, 2, 4);
insert into caravan_navi_comment values (10017, 2002, 130502, 1, 'ホウオウ', 'ショップへようこそ\\nこの鳳凰が、皆さんに\\n祝福を差し上げましょう', 1, '2024/06/15 15:00:00', '2024/09/22 14:59:59', -470.0, 0.0, 0.0, 1, 5);
insert into caravan_navi_comment values (10018, 2002, 130502, 1, 'ホウオウ', 'ほーちゃんと呼ぶ権利は\\n売っていませんよ？\\n騎士さんへの、特別です！', 2, '2024/06/15 15:00:00', '2024/09/22 14:59:59', -470.0, 0.0, 3.18, 2, 5);
insert into caravan_navi_comment values (10019, 2002, 130503, 4, 'ホウオウ', 'うﾞぇぇえんっ！まﾞだごの\\n格好になっぢゃいまじだ！\\n寄付をお願いじまず～っ！', 3, '2024/06/15 15:00:00', '2024/09/22 14:59:59', -470.0, 0.0, 0.0, 4, 5);
insert into caravan_navi_comment values (10020, 2002, 123301, 2, 'ネア', 'おっすー♪\\nなんでも交換してけー\\nカリザきゅん以外で', 1, '2024/06/15 15:00:00', '2024/09/22 14:59:59', -470.0, 0.0, 4.9, 1, 5);
insert into caravan_navi_comment values (10021, 2002, 123301, 2, 'ネア', 'ところで、騎士きゅんは\\nおいくら万ルピ？\\nジョーダンぬ・き・で♡', 2, '2024/06/15 15:00:00', '2024/09/22 14:59:59', -470.0, 0.0, 4.8, 1, 5);
